import { ComponentFixture, TestBed, fakeAsync, tick } from '@angular/core/testing';
import { LoginComponent } from './login.component';
import { ReactiveFormsModule } from '@angular/forms';
import { RouterTestingModule } from '@angular/router/testing';
import { of } from 'rxjs';

describe('LoginComponent (Standalone, hardcoded mocks)', () => {
    let component: LoginComponent;
    let fixture: ComponentFixture<LoginComponent>;

    beforeEach(async () => {
        await TestBed.configureTestingModule({
            imports: [
                LoginComponent,
                ReactiveFormsModule,
                RouterTestingModule // за RouterLink в template
            ],
        }).compileComponents();

        fixture = TestBed.createComponent(LoginComponent);
        component = fixture.componentInstance;

        // Hardcode mocks директно в компонента
        component['authService'] = {
            login: jasmine.createSpy('login').and.callFake((user: string, pass: string) => {
                if (user === 'success') return Promise.resolve();
                return Promise.reject({ message: 'Invalid credentials' });
            })
        } as any;

        component['router'] = {
            navigate: jasmine.createSpy('navigate')
        } as any;

        fixture.detectChanges();
    });

    it('should create the component', () => {
        expect(component).toBeTruthy();
    });

    it('should login successfully with correct credentials', fakeAsync(() => {
        component.loginForm.setValue({ emailOrUsername: 'success', password: '123' });
        component.onLogin();
        tick();

        expect(component['authService'].login).toHaveBeenCalled();
        expect(component['router'].navigate).toHaveBeenCalledWith(['/home']);
        expect(component.errorMessage).toBeNull();
    }));

    it('should show error message on failed login', fakeAsync(() => {
        component.loginForm.setValue({ emailOrUsername: 'fail', password: '123' });
        component.onLogin();
        tick();

        expect(component.errorMessage).toBe('Invalid credentials');
        expect(component['router'].navigate).not.toHaveBeenCalled();
    }));
});
